import random

from Arina.russian_language.class_1_tasks import make_choice_task, generate_unique_task
from Arina.english_language.class_2_topics import ENGLISH_CLASS_2_TOPICS


TASK_DATA = {
    "alphabet_en": [("Какая буква идёт после A?", ["B", "C", "D"], "B"), ("Какая буква идёт после C?", ["D", "B", "A"], "D"), ("Какая буква первая в алфавите?", ["A", "B", "C"], "A")],
    "sounds_reading": [("Как переводится слово cat?", ["кот", "собака", "рыба"], "кот"), ("Как переводится слово dog?", ["собака", "кот", "дом"], "собака"), ("Как переводится слово fish?", ["рыба", "птица", "мяч"], "рыба")],
    "greetings": [("Как сказать “привет” по-английски?", ["Hello", "Bye", "Red"], "Hello"), ("Как сказать “пока” по-английски?", ["Bye", "Hello", "Blue"], "Bye"), ("Good morning — это:", ["доброе утро", "спокойной ночи", "спасибо"], "доброе утро")],
    "family_en": [("Mother — это:", ["мама", "папа", "сестра"], "мама"), ("Father — это:", ["папа", "брат", "мама"], "папа"), ("Sister — это:", ["сестра", "брат", "бабушка"], "сестра")],
    "colors_en": [("Red — это:", ["красный", "синий", "зелёный"], "красный"), ("Blue — это:", ["синий", "жёлтый", "чёрный"], "синий"), ("Green — это:", ["зелёный", "красный", "белый"], "зелёный")],
    "numbers_1_10_en": [("Five — это:", ["пять", "четыре", "семь"], "пять"), ("Two — это:", ["два", "три", "десять"], "два"), ("Ten — это:", ["десять", "один", "шесть"], "десять")],
    "school_items_en": [("Book — это:", ["книга", "ручка", "стол"], "книга"), ("Pen — это:", ["ручка", "книга", "сумка"], "ручка"), ("Bag — это:", ["сумка", "карандаш", "дом"], "сумка")],
    "toys_en": [("Ball — это:", ["мяч", "кукла", "поезд"], "мяч"), ("Doll — это:", ["кукла", "мяч", "машина"], "кукла"), ("Car — это:", ["машина", "кубик", "мяч"], "машина")],
    "animals_en": [("Dog — это:", ["собака", "кошка", "слон"], "собака"), ("Cat — это:", ["кошка", "собака", "лиса"], "кошка"), ("Bird — это:", ["птица", "рыба", "лошадь"], "птица")],
    "food_en": [("Apple — это:", ["яблоко", "молоко", "сыр"], "яблоко"), ("Milk — это:", ["молоко", "хлеб", "яблоко"], "молоко"), ("Bread — это:", ["хлеб", "сыр", "сок"], "хлеб")],
    "home_rooms_en": [("Kitchen — это:", ["кухня", "сад", "дверь"], "кухня"), ("Room — это:", ["комната", "улица", "школа"], "комната"), ("House — это:", ["дом", "окно", "стул"], "дом")],
    "simple_phrases_en": [("Как переводится “I have a pen”?", ["У меня есть ручка", "Я красный", "Это дом"], "У меня есть ручка"), ("Как переводится “I like cats”?", ["Мне нравятся кошки", "У меня есть кот", "Я вижу дом"], "Мне нравятся кошки"), ("Как переводится “This is my book”?", ["Это моя книга", "Я читаю", "Это красный"], "Это моя книга")],
    "vocabulary_words_en_2": [("Sheep — это:", ["овца", "рыба", "сыр"], "овца"), ("Mouse — это:", ["мышь", "дом", "молоко"], "мышь"), ("Cheese — это:", ["сыр", "кот", "яблоко"], "сыр")],
}


def generate_english_class_2_topic_task(topic_id: str, used_questions: list[str] | None = None) -> dict:
    tasks = TASK_DATA.get(topic_id, TASK_DATA["alphabet_en"])
    task = generate_unique_task(lambda: make_choice_task(*random.choice(tasks), topic_id), used_questions)
    task["topic"] = topic_id
    task["topic_title"] = ENGLISH_CLASS_2_TOPICS.get(topic_id, {}).get("title", "Английский язык 2 класс")
    return task
